// SPDX-License-Identifier: GPL-2.0-only
/*
 * SpacemiT K1 USB 2.0 PHY driver
 *
 * Copyright (C) 2025 SpacemiT Corporation.  All rights reserved.
 */

#include <linux/bits.h>
#include <linux/clk.h>
#include <linux/err.h>
#include <linux/io.h>
#include <linux/mfd/syscon.h>
#include <linux/module.h>
#include <linux/phy/phy.h>
#include <linux/platform_device.h>
#include <linux/regmap.h>
#include <linux/reset.h>
#include <linux/usb/of.h>

/* USB 2.0 PHY register offsets */
#define USB2_PHY_POWER_CTL		0x00
#define USB2_PHY_CTRL			0x04
#define USB2_PHY_STATUS		0x08
#define USB2_PHY_TUNE			0x0c
#define USB2_PHY_INTR_EN		0x10
#define USB2_PHY_INTR_STS		0x14

/* Power control register bits */
#define PHY_POWER_DOWN			BIT(0)
#define PHY_SUSPEND			BIT(1)
#define PHY_SESSION_END			BIT(2)
#define PHY_OTG_ENABLE			BIT(3)
#define PHY_ID_PULLUP_EN		BIT(4)
#define PHY_DMPD				BIT(5)
#define PHY_DPPD				BIT(6)
#define PHY_CHARGEDET_EN		BIT(7)

/* PHY control register bits */
#define PHY_SUSPENDM			BIT(0)
#define PHY_TERM_SEL			BIT(1)
#define PHY_OP_MODE_SUSPENDM		BIT(2)
#define PHY_FS_LS_TERM_MASK		BIT(3)
#define PHY_XCVR_SEL			GENMASK(5, 4)
#define PHY_XCVR_NORMAL			0
#define PHY_XCVR_NON_DRIVING		1
#define PHY_XCVR_DISABLE		3
#define PHY_UTMI_CLK_SEL		GENMASK(7, 6)

/* Status register bits */
#define PHY_LINE_STATE			GENMASK(1, 0)
#define PHY_HOST_DISCON		BIT(2)
#define PHY_SESS_VALID			BIT(3)
#define PHY_VBUS_VALID			BIT(4)
#define PHY_B_VALID			BIT(5)
#define PHY_A_VALID			BIT(6)
#define PHY_ID_DIG			BIT(7)

/* Tuning register bits */
#define PHY_TXVREFTUNE			GENMASK(2, 0)
#define PHY_TXRISETUNE			GENMASK(4, 3)
#define PHY_SQRXTUNE			GENMASK(7, 5)

/* APMU system controller register for PHY mode */
#define PMUA_USB_PHY_CTRL0		0x0110
#define USB2_PORT_MODE			GENMASK(2, 0)
#define PORT_MODE_DEVICE		0x1
#define PORT_MODE_HOST			0x2

struct k1_usb2_phy {
	struct device *dev;
	void __iomem *regs;
	struct clk *clk;
	struct reset_control *rst;
	struct regmap *apmu;
	enum phy_mode mode;
};

static void k1_usb2_phy_power_up(struct k1_usb2_phy *phy)
{
	u32 val;

	val = readl(phy->regs + USB2_PHY_POWER_CTL);
	val &= ~(PHY_POWER_DOWN | PHY_SUSPEND);
	val |= PHY_OTG_ENABLE;
	writel(val, phy->regs + USB2_PHY_POWER_CTL);
}

static void k1_usb2_phy_power_down(struct k1_usb2_phy *phy)
{
	u32 val;

	val = readl(phy->regs + USB2_PHY_POWER_CTL);
	val |= PHY_POWER_DOWN | PHY_SUSPEND;
	writel(val, phy->regs + USB2_PHY_POWER_CTL);
}

static void k1_usb2_phy_set_host(struct k1_usb2_phy *phy)
{
	struct regmap *apmu = phy->apmu;
	u32 val;

	/* Configure PHY control register for host mode */
	val = readl(phy->regs + USB2_PHY_CTRL);
	val &= ~(PHY_XCVR_SEL | PHY_TERM_SEL | PHY_OP_MODE_SUSPENDM);
	val |= FIELD_PREP(PHY_XCVR_SEL, PHY_XCVR_NORMAL) | PHY_TERM_SEL;
	val |= PHY_SUSPENDM | PHY_OP_MODE_SUSPENDM;
	writel(val, phy->regs + USB2_PHY_CTRL);

	/* Disable device mode pull-downs */
	val = readl(phy->regs + USB2_PHY_POWER_CTL);
	val &= ~(PHY_DMPD | PHY_DPPD);
	writel(val, phy->regs + USB2_PHY_POWER_CTL);

	/* Set APMU port mode to host */
	regmap_update_bits(apmu, PMUA_USB_PHY_CTRL0, USB2_PORT_MODE,
			   FIELD_PREP(USB2_PORT_MODE, PORT_MODE_HOST));
}

static void k1_usb2_phy_set_device(struct k1_usb2_phy *phy)
{
	struct regmap *apmu = phy->apmu;
	u32 val;

	/* Configure PHY control register for device mode */
	val = readl(phy->regs + USB2_PHY_CTRL);
	val &= ~(PHY_XCVR_SEL | PHY_TERM_SEL);
	val |= FIELD_PREP(PHY_XCVR_SEL, PHY_XCVR_NORMAL) | PHY_TERM_SEL;
	val |= PHY_SUSPENDM | PHY_OP_MODE_SUSPENDM;
	writel(val, phy->regs + USB2_PHY_CTRL);

	/* Enable device mode pull-downs */
	val = readl(phy->regs + USB2_PHY_POWER_CTL);
	val |= PHY_DMPD | PHY_DPPD;
	writel(val, phy->regs + USB2_PHY_POWER_CTL);

	/* Set APMU port mode to device */
	regmap_update_bits(apmu, PMUA_USB_PHY_CTRL0, USB2_PORT_MODE,
			   FIELD_PREP(USB2_PORT_MODE, PORT_MODE_DEVICE));
}

static int k1_usb2_phy_init(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);
	int ret;

	ret = clk_prepare_enable(priv->clk);
	if (ret)
		return ret;

	/* Configure default PHY tuning values for USB 2.0 HS operation */
	writel(FIELD_PREP(PHY_TXVREFTUNE, 0x4) |
	       FIELD_PREP(PHY_TXRISETUNE, 0x2) |
	       FIELD_PREP(PHY_SQRXTUNE, 0x4),
	       priv->regs + USB2_PHY_TUNE);

	k1_usb2_phy_power_up(priv);

	return 0;
}

static int k1_usb2_phy_exit(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);

	k1_usb2_phy_power_down(priv);

	clk_disable_unprepare(priv->clk);

	return 0;
}

static int k1_usb2_phy_power_on(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);

	k1_usb2_phy_power_up(priv);

	return 0;
}

static int k1_usb2_phy_power_off(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);

	k1_usb2_phy_power_down(priv);

	return 0;
}

static int k1_usb2_phy_set_mode(struct phy *phy, enum phy_mode mode, int submode)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);

	switch (mode) {
	case PHY_MODE_USB_HOST:
		k1_usb2_phy_set_host(priv);
		break;
	case PHY_MODE_USB_DEVICE:
		k1_usb2_phy_set_device(priv);
		break;
	case PHY_MODE_USB_OTG:
		/* OTG mode requires ID pin sensing; configure as host
		 * initially and let the OTG driver manage switching.
		 */
		k1_usb2_phy_set_host(priv);
		break;
	default:
		return -EINVAL;
	}

	priv->mode = mode;

	return 0;
}

static int k1_usb2_phy_reset(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);
	u32 val;

	val = readl(priv->regs + USB2_PHY_POWER_CTL);
	val |= PHY_POWER_DOWN;
	writel(val, priv->regs + USB2_PHY_POWER_CTL);

	udelay(1);

	val &= ~PHY_POWER_DOWN;
	writel(val, priv->regs + USB2_PHY_POWER_CTL);

	return 0;
}

static const struct phy_ops k1_usb2_phy_ops = {
	.init		= k1_usb2_phy_init,
	.exit		= k1_usb2_phy_exit,
	.power_on	= k1_usb2_phy_power_on,
	.power_off	= k1_usb2_phy_power_off,
	.set_mode	= k1_usb2_phy_set_mode,
	.reset		= k1_usb2_phy_reset,
	.owner		= THIS_MODULE,
};

static int k1_usb2_phy_probe(struct platform_device *pdev)
{
	struct device *dev = &pdev->dev;
	struct phy_provider *phy_provider;
	struct k1_usb2_phy *priv;

	priv = devm_kzalloc(dev, sizeof(*priv), GFP_KERNEL);
	if (!priv)
		return -ENOMEM;

	priv->dev = dev;

	priv->clk = devm_clk_get(dev, NULL);
	if (IS_ERR(priv->clk))
		return dev_err_probe(dev, PTR_ERR(priv->clk),
				     "failed to get clock\n");

	priv->rst = devm_reset_control_get_optional_exclusive(dev, NULL);
	if (IS_ERR(priv->rst))
		return dev_err_probe(dev, PTR_ERR(priv->rst),
				     "failed to get reset\n");

	priv->regs = devm_platform_ioremap_resource(pdev, 0);
	if (IS_ERR(priv->regs))
		return dev_err_probe(dev, PTR_ERR(priv->regs),
				     "failed to map registers\n");

	priv->apmu = syscon_regmap_lookup_by_phandle(dev_of_node(dev),
						     "spacemit,apmu");
	if (IS_ERR(priv->apmu))
		return dev_err_probe(dev, PTR_ERR(priv->apmu),
				     "failed to get APMU syscon\n");

	priv->phy = devm_phy_create(dev, NULL, &k1_usb2_phy_ops);
	if (IS_ERR(priv->phy))
		return dev_err_probe(dev, PTR_ERR(priv->phy),
				     "failed to create PHY\n");

	phy_set_drvdata(priv->phy, priv);

	phy_provider = devm_of_phy_provider_register(dev, of_phy_simple_xlate);
	if (IS_ERR(phy_provider))
		return dev_err_probe(dev, PTR_ERR(phy_provider),
				     "failed to register PHY provider\n");

	return 0;
}

static const struct of_device_id k1_usb2_phy_of_match[] = {
	{ .compatible = "spacemit,k1-usb2-phy" },
	{ },
};
MODULE_DEVICE_TABLE(of, k1_usb2_phy_of_match);

static struct platform_driver k1_usb2_phy_driver = {
	.probe	= k1_usb2_phy_probe,
	.driver = {
		.of_match_table	= k1_usb2_phy_of_match,
		.name		= "spacemit-k1-usb2-phy",
	},
};
module_platform_driver(k1_usb2_phy_driver);

MODULE_DESCRIPTION("SpacemiT K1 USB 2.0 PHY driver");
MODULE_LICENSE("GPL");

